import dspy
from dspy.retrieve import ColBERTv2

class RetrievalQualityMonitor(dspy.Module):
    def __init__(self):
        self.retrieve = ColBERTv2(url='http://20.102.90.50:2017/wiki17_abstracts')

    def forward(self, query):
        passages = self.retrieve(query).passages
        query_emb = self.retrieve.encode_query(query)
        rel_scores = [self.cosine_sim(query_emb, p) for p in passages[:5]]
        avg_rel = sum(rel_scores) / len(rel_scores)

        if avg_rel < 0.7:
            print(f'LOW RETRIEVAL QUALITY: {query} -> avg_rel={avg_rel:.3f}')

        return dspy.Prediction(passages=passages, relevance=avg_rel)

    def cosine_sim(self, a, b):
        return dspy.settings.lm.inspect.embed(a) @ dspy.settings.lm.inspect.embed(b)

