class HybridRAG(dspy.Module):
    def __init__(self):
        self.dense = ColBERTv2(url='http://20.102.90.50:2017/wiki17_abstracts')
        self.sparse = dspy.BM25Retriever(documents=load_wiki_corpus())

    def forward(self, query):
        dense_results = self.dense(query, k=3)
        sparse_results = self.sparse(query, k=3)

        # Deduplicate and rerank
        combined = list(set(dense_results.passages + sparse_results.passages))
        reranked = self.rerank(query, combined)

        return dspy.Prediction(passages=reranked[:5])

    def rerank(self, query, passages):
        scores = []
        for passage in passages:
            score = self.dense.score([query], [passage])[0,0]
            scores.append(score)
        return [p for _, p in sorted(zip(scores, passages), reverse=True)]
